detailed_optimizations.code_changes:
将内层从 `for p { sum[p]=0; for s sum[p]+=A[r][q][s]*C4[s][p]; }` 改为 `for p sum[p]=0; for s { DATA_TYPE a = A[r][q][s]; for p sum[p] += a * C4[s][p]; }`。示例：
```cpp
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++) {
    for (p = 0; p < np; p++) sum[p] = 0;
    for (s = 0; s < np; s++) {
      DATA_TYPE a = A[r][q][s];
      for (p = 0; p < np; p++)
        sum[p] += a * C4[s][p];
    }
    for (p = 0; p < np; p++)
      A[r][q][p] = sum[p];
  }
```
这一步是最关键的结构性优化。

在交换循环后，让最内层 p 成为连续内存访问并显式提示编译器向量化。可引入局部指针：
```cpp
void kernel_doitgen(...,
  DATA_TYPE (* __restrict A)[NQ][NP],
  DATA_TYPE (* __restrict C4)[NP],
  DATA_TYPE * __restrict sum)
{
  ...
  for (r = 0; r < nr; r++)
    for (q = 0; q < nq; q++) {
      DATA_TYPE* __restrict sumv = sum;
      for (p = 0; p < np; p++) sumv[p] = 0;
      for (s = 0; s < np; s++) {
        DATA_TYPE a = A[r][q][s];
        DATA_TYPE* __restrict c4row = &C4[s][0];
        #pragma omp simd aligned(sumv, c4row:64)
        for (p = 0; p < np; p++)
          sumv[p] += a * c4row[p];
      }
      #pragma omp simd aligned(sumv:64)
      for (p = 0; p < np; p++)
        A[r][q][p] = sumv[p];
    }
}
```
若编译器支持，可加 `-O3 -march=native -ffast-math`。

当 np 较大时，将 p 分块，例如 BP=32/64，使一个块的 sum 保持在寄存器/L1 中：
```cpp
const int BP = 64;
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++)
    for (int pb = 0; pb < np; pb += BP) {
      int pend = (pb + BP < np) ? pb + BP : np;
      for (p = pb; p < pend; p++) sum[p] = 0;
      for (s = 0; s < np; s++) {
        DATA_TYPE a = A[r][q][s];
        #pragma omp simd
        for (p = pb; p < pend; p++)
          sum[p] += a * C4[s][p];
      }
      for (p = pb; p < pend; p++)
        A[r][q][p] = sum[p];
    }
```
进一步可手工展开 p 循环 4/8 路。

不同 (r,q) 对之间完全独立，但原代码中的 `sum` 是共享临时数组，必须私有化。推荐每线程私有局部缓冲：
```cpp
#pragma omp parallel for collapse(2) private(p,s)
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++) {
    DATA_TYPE local_sum[NP];
    for (p = 0; p < np; p++) local_sum[p] = 0;
    for (s = 0; s < np; s++) {
      DATA_TYPE a = A[r][q][s];
      #pragma omp simd
      for (p = 0; p < np; p++)
        local_sum[p] += a * C4[s][p];
    }
    for (p = 0; p < np; p++)
      A[r][q][p] = local_sum[p];
  }
```
若 NP 不是编译期常量，可用 `std::vector<DATA_TYPE> local_sum(np);` 或线程私有分配。

若允许额外内存，可为 A 的输出使用独立数组 `Aout`，避免 `sum -> A` 的单独 copy-back 成为显式阶段，并便于 BLAS/GPU 实现：
```cpp
for (r = 0; r < nr; r++)
  for (q = 0; q < nq; q++) {
    for (p = 0; p < np; p++) Aout[r][q][p] = 0;
    for (s = 0; s < np; s++) {
      DATA_TYPE a = A[r][q][s];
      #pragma omp simd
      for (p = 0; p < np; p++)
        Aout[r][q][p] += a * C4[s][p];
    }
  }
swap(A, Aout);
```
若必须原地，可保留 local_sum 后一次写回；该阶段已较轻，不建议过度优化。

初始化不是主瓶颈，但可用 OpenMP collapse：
```cpp
#pragma omp parallel for collapse(3)
for (i = 0; i < nr; i++)
  for (j = 0; j < nq; j++)
    for (k = 0; k < np; k++)
      A[i][j][k] = (DATA_TYPE)((i*j + k)%np) / np;

#pragma omp parallel for collapse(2)
for (i = 0; i < np; i++)
  for (j = 0; j < np; j++)
    C4[i][j] = (DATA_TYPE)(i*j % np) / np;
```
仅在计时包含初始化时有意义。
